children.text:
.scroller {
  position: relative;
  overflow-x: scroll;
  overflow-y: hidden;
  width: 300px;
  height: 100px;
  margin-bottom: 15px;
}

.grid-container {
  display: grid;
  grid-template-columns: 25% 25% 25% 25%;
  grid-template-rows: 100%;
  width: 400px;
  height: 90px;
}

.sticky {
  position: sticky;
  left: 50px;
}

.green {
  background-color: green;
}

.grid-item {
  width: 100%;
  height: 100%;
  grid-row: 1;
}

.indicator {
  position: absolute;
  background-color: red;
  width: 100px;
  height: 90px;
}

.padding {
  height: 1px;
  width: 700px;
}
